const sessao = $input.first().json;
const mensagens = sessao.mensagens || [];

const conversa_texto = mensagens.map((m, i) => `[${i+1}] ${m}`).join('\n');

const prompt = `VocÃª Ã© um especialista em anÃ¡lise de conversas comerciais de vendas.

Analise a seguinte conversa comercial e retorne um JSON estruturado:

CONVERSA:
${conversa_texto}

Retorne APENAS um JSON vÃ¡lido (sem markdown) com esta estrutura:
