    {"tipo": "preco|prazo|necessidade|confianca|concorrencia|outra", "contornada": true|false, "texto": "..."}
  ],
  "padrao_detectado": "descriÃ§Ã£o do padrÃ£o comportamental principal",
  "flags": ["objecao_ignorada", "tom_inadequado", etc]
}`;

return [{
  json: {
    sessao_id: sessao.sessao_id,
    remote_jid: sessao.remote_jid,
    prompt
  }
}];

// Extrai analise do Claude e monta INSERT SQL seguro
const sessao_id = $('Preparar Prompt Claude').first().json.sessao_id;
const claudeResponse = $input.first().json;

let analise = {};
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  const match = content.match(/\{[\s\S]*\}/);
  analise = JSON.parse(match ? match[0] : content);
} catch(e) {
  analise = {};
}

const totalTokens = (claudeResponse.usage?.input_tokens || 0) + (claudeResponse.usage?.output_tokens || 0);

// Defaults garantidos
const tipo_venda = analise.tipo_venda || 'consultiva';
const resultado = analise.resultado || 'pendente';
const tom = analise.tom_predominante || 'neutro';
const score = typeof analise.score_qualidade === 'number' ? Math.round(analise.score_qualidade) : 50;
const fases = Array.isArray(analise.fases) ? analise.fases : [];
const argumentos = Array.isArray(analise.argumentos) ? analise.argumentos : [];
const flags = Array.isArray(analise.flags) ? analise.flags : [];
const padrao = analise.padrao_detectado ? String(analise.padrao_detectado).slice(0, 250) : null;
const objecoes = Array.isArray(analise.objecoes) ? analise.objecoes : [];

// Escape SQL seguro
const sqlStr = (v) => "'" + String(v).replace(/'/g, "''") + "'";
const sqlJson = (v) => "'" + JSON.stringify(v).replace(/'/g, "''") + "'::jsonb";

const query = `INSERT INTO ml_comercial.conversas (
  sessao_id, tipo_venda, resultado, tom_predominante, score_qualidade,
  fases, argumentos, flags, padrao_detectado, analisado_por, tokens_usados, raw_analise
) VALUES (
  ${sqlStr(sessao_id)}::uuid,
  ${sqlStr(tipo_venda)}::ml_comercial.tipo_venda,
  ${sqlStr(resultado)}::ml_comercial.resultado_conversa,
  ${sqlStr(tom)}::ml_comercial.tom_comunicacao,
  ${score},
  ${sqlJson(fases)},
  ${sqlJson(argumentos)},
  ${sqlJson(flags)},
  ${padrao ? sqlStr(padrao) : 'NULL'},
  'conversation-analyst',
  ${totalTokens},
  ${sqlJson(analise)}
) ON CONFLICT DO NOTHING RETURNING id`;

return [{ json: { sessao_id, query, tokens_usados: totalTokens, objecoes } }];

